from flask import Flask, request
from prometheus_client import Counter, Gauge, Histogram, generate_latest

app = Flask(__name__)

# Metrics
REQUEST_COUNT = Counter('request_count', 'Total number of requests', ['method', 'endpoint'])
REQUEST_LATENCY = Histogram('request_latency_seconds', 'Request latency', ['method', 'endpoint'])
IN_PROGRESS = Gauge('in_progress_requests', 'In progress requests')
BUSINESS_METRIC = Gauge('business_metric', 'A business related metric')

@app.route('/metrics')
def metrics():
    return generate_latest()

@app.before_request
def before_request():
    IN_PROGRESS.inc()

@app.after_request
def after_request(response):
    REQUEST_COUNT.labels(request.method, request.path).inc()
    IN_PROGRESS.dec()
    return response

@app.route('/')
def home():
    with REQUEST_LATENCY.labels(request.method, '/').time():
        return "Hello, World!"

@app.route('/business')
def business():
    with REQUEST_LATENCY.labels(request.method, '/business').time():
        BUSINESS_METRIC.set(42)  # Example business metric
        return "Business Logic!"

if __name__ == '__main__':
    app.run()